Hi @DakuTree!

That is the expected behavior since the column already has a sort applied (i.e. a pseudo first-click has already been used). Clicking on the column will increment an internal counter to use the next sort.

That being said, you can add the following undocumented method inside the `initialized` callback to override the internal counter ([demo](http://jsfiddle.net/eY8uH/1890/)):

```js
$(function() {
  'use strict';
  $(".tablesorter").tablesorter({
    sortList: [[0, 'a'], [1, 'a']],
    headers: {
      1: {
        sortInitialOrder: "asc"
      }
    },
    initialized: function(table) {
    	var sortVars = table.config.sortVars;
      sortVars.forEach(function(el) {
      	// reset the internal counter
        el.count = -1;
      });
    }
  });
});
```

